import redis
import json
import sys
from typing import Any, Optional


class RedisLuaClient:
    """Redis client that executes Lua scripts for complex cache operations."""

    def __init__(self, host: str = "localhost", port: int = 6379, db: int = 0,
                 password: Optional[str] = None, decode_responses: bool = True):
        """Initialize Redis connection."""
        self.client = redis.Redis(
            host=host,
            port=port,
            db=db,
            password=password,
            decode_responses=decode_responses
        )
        self._script_cache = {}
        self._verify_connection()

    def _verify_connection(self):
        """Verify Redis connection is alive."""
        try:
            self.client.ping()
            print("[OK] Connected to Redis successfully.")
        except redis.ConnectionError as e:
            print(f"[ERROR] Failed to connect to Redis: {e}")
            raise

    def execute_lua_script(self, script: str, keys: list = None, args: list = None) -> Any:
        """
        Execute a Lua script against Redis.

        Args:
            script: Lua script code to execute
            keys: List of Redis keys referenced in the script (KEYS[1], KEYS[2], ...)
            args: List of arguments passed to the script (ARGV[1], ARGV[2], ...)

        Returns:
            Result of the Lua script execution
        """
        keys = keys or []
        args = args or []

        # Validate inputs
        if not script or not script.strip():
            raise ValueError("Lua script cannot be empty.")

        # Sanitize keys and args - convert all to strings for Redis
        sanitized_keys = [str(k) for k in keys]
        sanitized_args = [str(a) for a in args]

        try:
            result = self.client.eval(script, len(sanitized_keys), *sanitized_keys, *sanitized_args)
            return result
        except redis.exceptions.ResponseError as e:
            print(f"[ERROR] Lua script execution failed: {e}")
            raise
        except Exception as e:
            print(f"[ERROR] Unexpected error during script execution: {e}")
            raise

    def execute_cached_script(self, name: str, script: str, keys: list = None,
                               args: list = None) -> Any:
        """
        Execute a Lua script using EVALSHA for better performance.
        Scripts are registered once and then called by SHA hash.

        Args:
            name: A friendly name to cache the script under
            script: Lua script code
            keys: List of Redis keys
            args: List of arguments

        Returns:
            Result of the Lua script execution
        """
        keys = keys or []
        args = args or []

        sanitized_keys = [str(k) for k in keys]
        sanitized_args = [str(a) for a in args]

        if name not in self._script_cache:
            registered_script = self.client.register_script(script)
            self._script_cache[name] = registered_script
            print(f"[INFO] Script '{name}' registered and cached.")

        try:
            result = self._script_cache[name](keys=sanitized_keys, args=sanitized_args)
            return result
        except redis.exceptions.ResponseError as e:
            print(f"[ERROR] Cached script '{name}' execution failed: {e}")
            raise

    def list_cached_scripts(self) -> list:
        """List all cached script names."""
        return list(self._script_cache.keys())

    def clear_script_cache(self):
        """Clear the local script cache."""
        self._script_cache.clear()
        self.client.script_flush()
        print("[OK] Script cache cleared.")


