def interactive_mode(client: RedisLuaClient):
    """Run the interactive CLI for executing Lua scripts."""
    print("\n" + "=" * 60)
    print("  Redis Lua Script Executor - Interactive Mode")
    print("=" * 60)
    print("\nCommands:")
    print("  exec       - Execute a custom Lua script")
    print("  templates  - List available script templates")
    print("  run <name> - Run a template script")
    print("  cached     - List cached scripts")
    print("  flush      - Clear script cache")
    print("  help       - Show this help message")
    print("  quit       - Exit")
    print()

    while True:
        try:
            command = input("\nredis-lua> ").strip()

            if not command:
                continue

            if command.lower() in ("quit", "exit", "q"):
                print("Goodbye!")
                break

            elif command.lower() == "help":
                print("\nCommands:")
                print("  exec       - Execute a custom Lua script")
                print("  templates  - List available script templates")
                print("  run <name> - Run a template script")
                print("  cached     - List cached scripts")
                print("  flush      - Clear script cache")
                print("  quit       - Exit")

            elif command.lower() == "exec":
                _interactive_exec(client)

            elif command.lower() == "templates":
                _list_templates()

            elif command.lower().startswith("run "):
                template_name = command[4:].strip()
                _run_template(client, template_name)

            elif command.lower() == "cached":
                cached = client.list_cached_scripts()
                if cached:
                    print(f"Cached scripts: {', '.join(cached)}")
                else:
                    print("No cached scripts.")

            elif command.lower() == "flush":
                client.clear_script_cache()

            else:
                print(f"Unknown command: '{command}'. Type 'help' for available commands.")

        except KeyboardInterrupt:
            print("\nGoodbye!")
            break
        except EOFError:
            print("\nGoodbye!")
            break
        except Exception as e:
            print(f"[ERROR] {e}")


def _interactive_exec(client: RedisLuaClient):
    """Handle interactive script execution."""
    print("\nEnter your Lua script (type 'END' on a new line to finish):")
    lines = []
    while True:
        try:
            line = input("... ")
            if line.strip() == "END":
                break
            lines.append(line)
        except EOFError:
            break

    script = "\n".join(lines)
    if not script.strip():
        print("[WARN] Empty script, skipping.")
        return

    # Get keys
    keys_input = input("Enter KEYS (comma-separated, or empty): ").strip()
    keys = [k.strip() for k in keys_input.split(",") if k.strip()] if keys_input else []

    # Get args
    args_input = input("Enter ARGV (comma-separated, or empty): ").strip()
    args = [a.strip() for a in args_input.split(",") if a.strip()] if args_input else []

    # Ask if should cache
    cache_input = input("Cache this script? (name/no): ").strip()

    print(f"\n[INFO] Executing script with {len(keys)} keys and {len(args)} args...")

    try:
        if cache_input and cache_input.lower() != "no":
            result = client.execute_cached_script(cache_input, script, keys, args)
        else:
            result = client.execute_lua_script(script, keys, args)

        print(f"[RESULT] {_format_result(result)}")
    except Exception as e:
        print(f"[ERROR] Script execution failed: {e}")


def _list_templates():
    """List available Lua script templates."""
    print("\nAvailable Script Templates:")
    print("-" * 40)
    for name, info in LUA_SCRIPTS.items():
        print(f"\n  {name}")
        print(f"    Description: {info['description']}")
        print(f"    Keys: {', '.join(info['keys_hint'])}")
        print(f"    Args: {', '.join(info['args_hint']) if info['args_hint'] else 'none'}")


def _run_template(client: RedisLuaClient, template_name: str):
    """Run a template script interactively."""
    if template_name not in LUA_SCRIPTS:
        print(f"[ERROR] Template '{template_name}' not found. Use 'templates' to list available.")
        return

    template = LUA_SCRIPTS[template_name]
    print(f"\nRunning template: {template_name}")
    print(f"Description: {template['description']}")
    print(f"Expected keys: {', '.join(template['keys_hint'])}")
    print(f"Expected args: {', '.join(template['args_hint']) if template['args_hint'] else 'none'}")

    # Get keys
    keys_input = input(f"\nEnter KEYS (comma-separated): ").strip()
    keys = [k.strip() for k in keys_input.split(",") if k.strip()] if keys_input else []

    # Get args
    args_input = input("Enter ARGV (comma-separated): ").strip()
    args = [a.strip() for a in args_input.split(",") if a.strip()] if args_input else []

    try:
        result = client.execute_cached_script(template_name, template["script"], keys, args)
        print(f"[RESULT] {_format_result(result)}")
    except Exception as e:
        print(f"[ERROR] Template execution failed: {e}")


def _format_result(result: Any) -> str:
    """Format script result for display."""
    if isinstance(result, list):
        return json.dumps(result, default=str, indent=2)
    elif isinstance(result, bytes):
        return result.decode("utf-8", errors="replace")
    else:
        return str(result)


