def main():
    """Main entry point."""
    import argparse

    parser = argparse.ArgumentParser(description="Redis Lua Script Executor")
    parser.add_argument("--host", default="localhost", help="Redis host (default: localhost)")
    parser.add_argument("--port", type=int, default=6379, help="Redis port (default: 6379)")
    parser.add_argument("--db", type=int, default=0, help="Redis database (default: 0)")
    parser.add_argument("--password", default=None, help="Redis password")
    parser.add_argument("--mode", choices=["interactive", "demo", "exec"],
                        default="interactive",
                        help="Execution mode (default: interactive)")
    parser.add_argument("--script", help="Lua script to execute (for exec mode)")
    parser.add_argument("--script-file", help="File containing Lua script (for exec mode)")
    parser.add_argument("--keys", nargs="*", default=[], help="Keys for the script")
    parser.add_argument("--args", nargs="*", default=[], help="Arguments for the script")

    args = parser.parse_args()

    try:
        client = RedisLuaClient(
            host=args.host,
            port=args.port,
            db=args.db,
            password=args.password
        )
    except redis.ConnectionError:
        print("Failed to connect to Redis. Please check your connection settings.")
        sys.exit(1)

    if args.mode == "demo":
        demo_mode(client)

    elif args.mode == "exec":
        script = args.script
        if args.script_file:
            with open(args.script_file, "r") as f:
                script = f.read()

        if not script:
            print("[ERROR] No script provided. Use --script or --script-file.")
            sys.exit(1)

        try:
            result = client.execute_lua_script(script, args.keys, args.args)
            print(f"Result: {_format_result(result)}")
        except Exception as e:
            print(f"[ERROR] {e}")
            sys.exit(1)

    else:
        interactive_mode(client)


if __name__ == "__main__":
    main()